#include <bits/stdc++.h>
#define ull unsigned long long
#define mk(x,y) make_pair(x,y)
#define PII pair<int,int>
#define NoAns puts("-1");
#define FOR(i,j,k) for(int i=(j);i<=(k);++i)
#define ROF(i,j,k) for(int i=(j);i>=(k);--i)
#define FOI(a,b) for(auto a : b)
#define Yes puts("Yes");
#define No puts("No");
#define llinf 0x3f3f3f3f3f3f3f3f
#define inf 0x3f3f3f3f
#define ll long long
#define snd second
#define fst first
#define il inline
#define pb(x) push_back(x)
#define CI const int
#define cl(x) memset(x,0,sizeof x)
#define cli(x) memset(x,0x3f,sizeof x)
#define lowbit(x) (x&(-x))
#define wh(x) while(x)
#define gc() getchar()
#define pc(x) putchar(x)
#define NP namespace
using NP std;
il ll read()
{
    ll x=0,f=1;char ch=gc();
    wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
    wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=gc();}
    return x*f;
}
void write(ll x)
{
    if(x<0)pc('-'),x=-x;
    if(x>9)write(x/10);
    pc(x%10+'0');
}
void writeln(ll x)
{
    write(x);
    puts("");
    return;
}
CI MAXN=1e3+5;
int b[MAXN],num[MAXN][MAXN],a[MAXN],n,k,ans;
bool DFS(int u)
{
	if(a[u]>0)
    {
        return true;
    }
	if(b[u]==0)
    {
        return false;
    }
    ROF(i,b[u],1)
    {
        if(!DFS(num[u][i]))
        {
            return false; 
        }
    }
    FOR(i,1,b[u])
    {
        --a[num[u][i]]; 
    }
	++a[u]; 
	return true;
}
int main(void)
{
	n=read();
	FOR(i,1,n)
    {
		a[i]=read();
    }
    ans=a[n],a[n]=0;
	k=read();
	FOR(i,1,k)
    {
		int x=read();
        b[x]=read();
		FOR(j,1,b[x])
        {
            num[x][j]=read();
        }
	}
	wh(DFS(n))
    {
        ++ans,--a[n];
    }
    write(ans);
	return false;
}
